function LSdkQianxiTrack:RegTrackEvent()
    local eventReg = self._behaviour

    eventReg:AddEventHandler(EventNames.ON_JOIN_GUILD, function()
        local guildInfo = gModelGuild and gModelGuild:GetSelfGuildInfo() or nil
        if not guildInfo then return end
        local afName = LSdkQianxiTrack.AF_JOINALLIANCE
        if self:IsTrackRecorded(afName) then
            return
        end
        self:RecordedTrack(afName)
        self:SendTrackEvent(afName, "", false)
    end)

    eventReg:AddEventHandler(EventNames.ON_CALL_HERO_REWARD, function(...)
        self:OnCallHeroReward(...)
    end)

    eventReg:AddEventHandler(EventNames.FAVORABILITY_EXP_CHANGED, function(...)
        self:OnGardenPlay(...)
    end)
    eventReg:AddEventHandler(EventNames.FAVORABILITY_INTERACT, function(...)
        self:OnGardenPlay(...)
    end)

    eventReg:AddEventHandler(EventNames.ON_PLAYER_LEVEL_CHANGE, function(...)
        self:OnPlayerLevelChange(...)
    end)

    eventReg:AddEventHandler(EventNames.ON_CHARGE_MONEY_CHANGE, function(...)
        self:OnChargeMoneyChange(...)
    end)

    eventReg:AddEventHandler(EventNames.ON_CHARGE_MONEY_SET, function(...)
        if gModelPlayer and gModelPlayer.chargeMoney then
            local chargeMoney = gModelPlayer.chargeMoney
            if self._lastMoney ~= chargeMoney then
                self:OnChargeMoneyChange(0,  chargeMoney)
            end
        end
    end)

    eventReg:AddEventHandler(EventNames.ON_POWER_CHANGE, function(...)
        self:OnPowerChange(...)
    end)
end

function LSdkQianxiTrack:SendTrackEvent(eventName, ...)
    if LOG_INFO_ENABLED then
        printInfoN("trackEvent", eventName, ...)
    end
    gLSdkImpl:CallMethod(LSdkMethod.TrackEvent, eventName, ...)
end

function LSdkQianxiTrack:IsTrackRecorded(afName)
    local ids = gModelPlayer and gModelPlayer:GetFireOneTimeEventIds() or {}
    local id = LSdkQianxiTrack.AF_IDS[afName]
    if not id then return true end
    if ids[id] then
        return true
    else
        return false
    end
end

function LSdkQianxiTrack:RecordedTrack(afName)
    if not gModelPlayer then return end
    local id = LSdkQianxiTrack.AF_IDS[afName]
    if not id then return end
    gModelPlayer:OnFireOnetimeEventReq(id)
end

function LSdkQianxiTrack:OnCallHeroReward(callNum, callRefId, itemList, fixedReward)
    local nameList = {
        [1001] = "nvshen" -- 高级召唤
    }
    local name = nameList[callRefId]
    if string.isempty(name) then return end
    local afName = LSdkQianxiTrack.AF_GACHA10REN
    if self:IsTrackRecorded(afName) then
        return
    end
    self:RecordedTrack(afName)
    self:SendTrackEvent(afName, "", false)
end

function LSdkQianxiTrack:OnGardenPlay()
    local afName = LSdkQianxiTrack.AF_FIRST_PRESENT
    if self:IsTrackRecorded(afName) then return end
    self:RecordedTrack(afName)
    self:SendTrackEvent(afName,"",false)
end

local _LevelList = {
    {level=2, afName = LSdkQianxiTrack.AF_UPGRADEROLE_2},
    {level=3, afName = LSdkQianxiTrack.AF_UPGRADEROLE_3},
    {level=8, afName = LSdkQianxiTrack.AF_UPGRADEROLE_8},
    {level=10, afName = LSdkQianxiTrack.AF_UPGRADEROLE_10},
