    {level=80, afName = LSdkQianxiTrack.AF_UPGRADEROLE_80},
}
function LSdkQianxiTrack:OnPlayerLevelChange(oldLevel, newLevel)
    local afName
    local checkList = _LevelList
    for k, v in ipairs(checkList) do
        local level = v.level
        if oldLevel < level and newLevel >= level then
            afName = v.afName
            if not self:IsTrackRecorded(afName) then
                self:RecordedTrack(afName)
                self:SendTrackEvent(afName, "", false)
            end
        end
    end
end

local _moneyList = {
    {money=599, afName = LSdkQianxiTrack.AF_PAY_5_99},
    {money=1999, afName = LSdkQianxiTrack.AF_PAY_19_99},
    {money=4999, afName = LSdkQianxiTrack.AF_PAY_49_99},
    {money=9999, afName = LSdkQianxiTrack.AF_PAY_99_99},
}
function LSdkQianxiTrack:OnChargeMoneyChange(oldMoney, newMoney)
    oldMoney = oldMoney or 0
    newMoney = newMoney or 0
    if not self._lastMoney then
        self._lastMoney = oldMoney
    end
    local afName = LSdkQianxiTrack.AF_FIRSTPURCHASE
    if newMoney > 0 and not self:IsTrackRecorded(afName) then
        self:RecordedTrack(afName)
        self:SendTrackEvent(afName, "", false)
    end

    oldMoney = self._lastMoney
    self._lastMoney = newMoney

    local checkList = _moneyList

    for k, v in ipairs(checkList) do
        local money = v.money
        if oldMoney < money and newMoney >= money then
            afName = v.afName
            if not self:IsTrackRecorded(afName) then
                self:RecordedTrack(afName)
                self:SendTrackEvent(afName, "", false)
            end
        end
    end
end

local _powerList = {
    {power=20000, afName = LSdkQianxiTrack.AF_POWER_2},
    {power=100000, afName = LSdkQianxiTrack.AF_POWER_10},
    {power=200000, afName = LSdkQianxiTrack.AF_POWER_20},
    {power=500000, afName = LSdkQianxiTrack.AF_POWER_50},
    {power=1000000, afName = LSdkQianxiTrack.AF_POWER_100},
    {power=2000000, afName = LSdkQianxiTrack.AF_POWER_200},
}
function LSdkQianxiTrack:OnPowerChange(showType,key,power)
    if(showType ~= 0) then return end
    key = tostring(key)
    local cmpKey = tostring(LCombatTypeConst.COMBAT_MAIN)
    if( key ~= cmpKey) then return end
    if not self._maxPower then
        self._maxPower = 0
    end
    if power < self._maxPower then return end

    local oldPower = self._maxPower

    self._maxPower = power

    local checkList = _powerList
    local afName
    for k, v in ipairs(checkList) do
        local checkPower = v.power
        if oldPower < checkPower and power >= checkPower then
            afName = v.afName
            if not self:IsTrackRecorded(afName) then
                self:RecordedTrack(afName)
                self:SendTrackEvent(afName, "", false)
            end
        end
    end
end
